{"file_path":"/project/ktlint-ruleset-standard/src/test/kotlin/com/pinterest/ktlint/ruleset/standard/rules/IndentationRuleParenthesizedExpressionInIfBlockTest.kt","content":"package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CODE_STYLE_PROPERTY
import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CodeStyleValue.ktlint_official
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

internal class IndentationRuleParenthesizedExpressionInIfBlockTest {
    private val indentationRuleAssertThat = assertThatRule { IndentationRule() }

    @Test
    fun `Given a parenthesized expression inside an if block then do not require an extra indentation level`() {
        val code =
            """
            fun foo(condition1: Boolean, condition2: Boolean, condition3: Boolean): Boolean {
                val pass = if (condition1) {
                    (
                        condition2
                    )
                } else {
                    condition3
                }
                return pass
            }
            """.trimIndent()

        indentationRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
            .hasNoLintViolations()
    }

    @Test
    fun `Given a multiline if condition and a parenthesized expression in the then block then align the parentheses consistently`() {
        val code =
            """
            fun foo(condition1: Boolean, condition2: Boolean, condition3: Boolean): Boolean {
                return if (
                    condition1
                ) {
                    (
                        condition2
                    )
                } else {
                    condition3
                }
            }
            """.trimIndent()

        indentationRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
            .hasNoLintViolations()
    }
}
"}

